class Student
{
public:
    ~Student() // destructor — same name as the class, prefixed with ~, no return type
    {
        cout << "Student object destroyed" << endl;
    }
};

#include <iostream>

using namespace std;

class Student
{
public:
    Student()
    {
        cout << "Student created" << endl;
    }

    ~Student()
    {
        cout << "Student destroyed" << endl;
    }
};

int main()
{
    cout << "Before" << endl;

    Student s1;

    cout << "After" << endl;

    return 0;
}

class Buffer
{
private:
    int *data;

public:
    Buffer()
    {
        data = new int[100]; // heap memory acquired in the constructor
    }

    ~Buffer()
    {
        delete[] data; // released automatically when the Buffer is destroyed
    }
};

